"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[812],{8529:i=>{i.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/intro/","label":"01 - Physical AI Foundations","docId":"intro/intro","unlisted":false},{"type":"category","label":"Module 2: ROS 2 Fundamentals","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/ros2/ros2-intro-architecture","label":"2.1 - Intro & Architecture","docId":"ros2/ros2-intro-architecture","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/ros2/ros2-workspace-setup","label":"2.2 - Workspace Setup","docId":"ros2/ros2-workspace-setup","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/ros2/ros2-python-nodes","label":"2.3 - Python Nodes","docId":"ros2/ros2-python-nodes","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/ros2/ros2-topics-services","label":"2.4 - Topics vs. Services","docId":"ros2/ros2-topics-services","unlisted":false}],"href":"/Physical-AI-Humanoid-Robotics-Textbook/ros2/"},{"type":"category","label":"Module 3: Digital Twin Simulations","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/digital-twin/gazebo-comparison","label":"3.1 - Gazebo Comparison","docId":"digital-twin/gazebo-comparison","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/digital-twin/urdf-vs-sdf","label":"3.2 - URDF vs. SDF","docId":"digital-twin/urdf-vs-sdf","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/digital-twin/unity-robotics-hub","label":"3.3 - Unity Robotics Hub","docId":"digital-twin/unity-robotics-hub","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/digital-twin/building-a-world","label":"3.4 - Building a World","docId":"digital-twin/building-a-world","unlisted":false}],"href":"/Physical-AI-Humanoid-Robotics-Textbook/digital-twin/"},{"type":"category","label":"Module 4: NVIDIA Isaac Sim","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/isaac-sim/installing-omniverse","label":"4.1 - Installing Omniverse","docId":"isaac-sim/installing-omniverse","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/isaac-sim/usd-fundamentals","label":"4.2 - USD Fundamentals","docId":"isaac-sim/usd-fundamentals","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/isaac-sim/importing-robots","label":"4.3 - Importing Robots","docId":"isaac-sim/importing-robots","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/isaac-sim/isaac-lab-intro","label":"4.4 - Isaac Lab Intro","docId":"isaac-sim/isaac-lab-intro","unlisted":false}],"href":"/Physical-AI-Humanoid-Robotics-Textbook/isaac-sim/"},{"type":"category","label":"Module 5: VLA Models","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/vision-language-action/vision-transformers","label":"5.1 - Vision Transformers","docId":"vision-language-action/vision-transformers","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/vision-language-action/clip-and-grounding","label":"5.2 - CLIP & Grounding","docId":"vision-language-action/clip-and-grounding","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/vision-language-action/openvla-setup","label":"5.3 - OpenVLA / RT-2 Setup","docId":"vision-language-action/openvla-setup","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/vision-language-action/ros2-vla-bridge","label":"5.4 - ROS 2 VLA Bridge","docId":"vision-language-action/ros2-vla-bridge","unlisted":false}],"href":"/Physical-AI-Humanoid-Robotics-Textbook/vision-language-action/"},{"type":"category","label":"Module 6: Walking & Grasping","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/humanoid-control/inverse-kinematics","label":"6.1 - FK & IK","docId":"humanoid-control/inverse-kinematics","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/humanoid-control/moveit2-basics","label":"6.2 - MoveIt 2 Basics","docId":"humanoid-control/moveit2-basics","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/humanoid-control/gait-generation","label":"Chapter 3: Gait Generation","docId":"humanoid-control/gait-generation","unlisted":false},{"type":"link","href":"/Physical-AI-Humanoid-Robotics-Textbook/humanoid-control/reinforcement-learning-control","label":"Chapter 4: Reinforcement Learning Control","docId":"humanoid-control/reinforcement-learning-control","unlisted":false}],"href":"/Physical-AI-Humanoid-Robotics-Textbook/humanoid-control/"}]},"docs":{"digital-twin/building-a-world":{"id":"digital-twin/building-a-world","title":"Module 3.4: Building a Simple World","description":"Creating custom simulation environments is essential for tailored robotics development and testing. Whether you need a simple maze for navigation, a complex factory floor, or a dynamic outdoor scene, simulators provide the tools to build these virtual worlds. This chapter will guide you through creating a basic maze environment in Gazebo.","sidebar":"tutorialSidebar"},"digital-twin/digital-twin-overview":{"id":"digital-twin/digital-twin-overview","title":"Module 3: Digital Twin Simulations Overview","description":"Welcome to Module 3, where we delve into the world of digital twins and robotics simulation. This module is critical for understanding how to develop and test complex robotic systems in virtual environments before deploying them to physical hardware. We will explore the benefits of simulation, address the challenges of the Sim2Real gap, and introduce key simulation tools.","sidebar":"tutorialSidebar"},"digital-twin/gazebo-comparison":{"id":"digital-twin/gazebo-comparison","title":"Module 3.1: Gazebo Classic vs. Ignition","description":"Gazebo has been the de facto standard simulator in the ROS community for many years. However, with the evolution of robotics and simulation needs, a new generation of Gazebo, often referred to as Gazebo Ignition (or just Gazebo), has emerged. This chapter will compare these two powerful simulation platforms.","sidebar":"tutorialSidebar"},"digital-twin/unity-robotics-hub":{"id":"digital-twin/unity-robotics-hub","title":"Module 3.3: Unity Robotics Hub","description":"While Gazebo is prevalent in the ROS community, Unity offers a powerful alternative for high-fidelity visualization, advanced physics, and rich interactive environments, especially when photo-realistic rendering or complex human-robot interaction is desired. The Unity Robotics Hub provides tools to integrate Unity projects with ROS 2, enabling sophisticated simulation capabilities.","sidebar":"tutorialSidebar"},"digital-twin/urdf-vs-sdf":{"id":"digital-twin/urdf-vs-sdf","title":"Module 3.2: URDF vs. SDF","description":"When working with robotic simulators like Gazebo, you need a way to describe your robot\'s physical properties (links, joints, sensors) and the environment it operates in. ROS and Gazebo primarily use two XML-based formats for this purpose: URDF and SDF. This chapter will explain the differences and appropriate use cases for each.","sidebar":"tutorialSidebar"},"humanoid-control/gait-generation":{"id":"humanoid-control/gait-generation","title":"Chapter 3: Gait Generation","description":"Bipedal Locomotion","sidebar":"tutorialSidebar"},"humanoid-control/humanoid-control-overview":{"id":"humanoid-control/humanoid-control-overview","title":"Module 6: Walking & Grasping Overview","description":"Welcome to Module 6, the culmination of our journey into Physical AI and Humanoid Robotics. This module tackles two of the most challenging problems in robotics: locomotion (maintaining balance and moving in complex environments) and manipulation (interacting with objects dexterously).","sidebar":"tutorialSidebar"},"humanoid-control/inverse-kinematics":{"id":"humanoid-control/inverse-kinematics","title":"Module 6.1: Forward and Inverse Kinematics","description":"To precisely control a robotic arm or a humanoid limb, we need to understand the relationship between the robot\'s joint angles and the position and orientation of its end-effector (e.g., a gripper or hand). This relationship is defined by kinematics, which can be broadly categorized into Forward Kinematics (FK) and Inverse Kinematics (IK).","sidebar":"tutorialSidebar"},"humanoid-control/moveit2-basics":{"id":"humanoid-control/moveit2-basics","title":"Module 6.2: MoveIt 2 Basics for Motion Planning","description":"Motion planning is a fundamental aspect of robotic manipulation, ensuring that a robot can move its limbs or end-effector from a starting configuration to a target configuration without colliding with itself, obstacles in the environment, or even the objects it intends to interact with. MoveIt 2 is the most widely used software suite for mobile manipulation in ROS 2, providing a comprehensive set of tools for motion planning, manipulation, and control.","sidebar":"tutorialSidebar"},"humanoid-control/reinforcement-learning-control":{"id":"humanoid-control/reinforcement-learning-control","title":"Chapter 4: Reinforcement Learning Control","description":"Learning to Walk","sidebar":"tutorialSidebar"},"intro/intro":{"id":"intro/intro","title":"Module 1: Physical AI Foundations","description":"Welcome to \\"Physical AI & Humanoid Robotics,\\" an advanced course designed to equip you with the knowledge and practical skills to develop intelligent systems that interact with the physical world. This module lays the groundwork by defining Physical AI and distinguishing it from its generative counterparts.","sidebar":"tutorialSidebar"},"isaac-sim/importing-robots":{"id":"isaac-sim/importing-robots","title":"Module 4.3: Importing Robots into Isaac Sim","description":"To simulate a robot in NVIDIA Isaac Sim, you first need to bring its model into the Omniverse environment. The Unified Robot Description Format (URDF) is a common way to describe robots in the ROS ecosystem. Isaac Sim provides a powerful \\"URDF Importer\\" extension to facilitate this process, converting your URDF robot description into a USD asset.","sidebar":"tutorialSidebar"},"isaac-sim/installing-omniverse":{"id":"isaac-sim/installing-omniverse","title":"Module 4.1: Installing NVIDIA Omniverse","description":"To begin working with NVIDIA Isaac Sim, you first need to install the NVIDIA Omniverse Launcher and set up the necessary components. This chapter will guide you through the process of getting Omniverse and Isaac Sim ready on your system.","sidebar":"tutorialSidebar"},"isaac-sim/isaac-lab-intro":{"id":"isaac-sim/isaac-lab-intro","title":"Module 4.4: Introduction to Isaac Lab","description":"NVIDIA Isaac Lab, formerly known as Orbit, is a powerful framework for developing and training reinforcement learning (RL) policies for robotics within NVIDIA Isaac Sim. It provides a robust, highly parallel, and scalable environment for RL research and application.","sidebar":"tutorialSidebar"},"isaac-sim/isaac-sim-overview":{"id":"isaac-sim/isaac-sim-overview","title":"Module 4: NVIDIA Isaac Sim Overview","description":"Welcome to Module 4, where we explore NVIDIA Isaac Sim, a powerful robotics simulation platform built on NVIDIA Omniverse. This module will introduce you to the core concepts of Omniverse, its components like Nucleus, and the significant advantages of leveraging GPU-accelerated simulation for robotics and AI development.","sidebar":"tutorialSidebar"},"isaac-sim/usd-fundamentals":{"id":"isaac-sim/usd-fundamentals","title":"Module 4.2: USD Fundamentals","description":"Universal Scene Description (USD) is a powerful, open-source 3D scene description technology developed by Pixar Animation Studios. It\'s the core technology behind NVIDIA Omniverse and plays a crucial role in creating complex, collaborative, and scalable virtual worlds for robotics. This chapter will introduce you to the fundamentals of USD.","sidebar":"tutorialSidebar"},"ros2/ros2-intro-architecture":{"id":"ros2/ros2-intro-architecture","title":"Module 2.1: Introduction and Architecture","description":"This chapter introduces the fundamental architecture of ROS 2, comparing it to its predecessor, ROS 1, and detailing the core components that form the ROS Graph.","sidebar":"tutorialSidebar"},"ros2/ros2-overview":{"id":"ros2/ros2-overview","title":"Module 2: ROS 2 Basics Overview","description":"Welcome to Module 2, where we dive into the Robot Operating System 2 (ROS 2), the foundational middleware for modern robotics development. This module will introduce you to the core concepts, architecture, and practical tools needed to build sophisticated robotic applications.","sidebar":"tutorialSidebar"},"ros2/ros2-python-nodes":{"id":"ros2/ros2-python-nodes","title":"Module 2.3: Coding Python Nodes","description":"One of the strengths of ROS 2 is its support for multiple programming languages. Python is a popular choice due to its readability and extensive libraries, making it ideal for rapid prototyping and complex AI algorithms. In this chapter, we will learn how to write a simple ROS 2 Python node.","sidebar":"tutorialSidebar"},"ros2/ros2-topics-services":{"id":"ros2/ros2-topics-services","title":"Module 2.4: Topics vs. Services","description":"ROS 2 provides several communication mechanisms, each suited for different scenarios. While Topics are excellent for streaming data, sometimes a robot needs to request a specific action or piece of information and receive a direct response. This is where Services come into play. This chapter will clarify the distinction between Topics and Services and guide you on when to use each.","sidebar":"tutorialSidebar"},"ros2/ros2-workspace-setup":{"id":"ros2/ros2-workspace-setup","title":"Module 2.2: Workspace Setup","description":"To begin developing with ROS 2, you need to set up a dedicated workspace. A ROS 2 workspace is a directory where you store your ROS 2 packages, build them, and manage their dependencies. This chapter will guide you through creating and building a typical ROS 2 workspace.","sidebar":"tutorialSidebar"},"vision-language-action/clip-and-grounding":{"id":"vision-language-action/clip-and-grounding","title":"Module 5.2: CLIP and Grounding","description":"For robots to truly understand and act upon human commands, they need to bridge the gap between visual perception and natural language. This is where models like CLIP (Contrastive Language-Image Pre-training) and the concept of grounding become invaluable. This chapter explores how these technologies enable robots to connect textual descriptions with visual reality.","sidebar":"tutorialSidebar"},"vision-language-action/openvla-setup":{"id":"vision-language-action/openvla-setup","title":"Module 5.3: Setting up OpenVLA / RT-2","description":"To truly understand Vision-Language-Action (VLA) models, hands-on experience is invaluable. This chapter will guide you through setting up and running a powerful VLA model locally, focusing on either OpenVLA or Google\'s RT-2 (Robotics Transformer 2) with quantized models for efficient execution on consumer-grade hardware.","sidebar":"tutorialSidebar"},"vision-language-action/ros2-vla-bridge":{"id":"vision-language-action/ros2-vla-bridge","title":"Module 5.4: ROS 2 VLA Bridge","description":"Vision-Language-Action (VLA) models generate high-level action tokens or continuous action values that represent the robot\'s intended behavior based on visual and linguistic inputs. For a physical robot operating within the ROS 2 ecosystem, these abstract outputs need to be translated into low-level commands that its actuators can understand and execute. This is the role of the ROS 2 VLA Bridge.","sidebar":"tutorialSidebar"},"vision-language-action/vision-transformers":{"id":"vision-language-action/vision-transformers","title":"Module 5.1: Vision Transformers","description":"For years, Convolutional Neural Networks (CNNs) were the undisputed champions of computer vision. However, with the groundbreaking success of Transformers in Natural Language Processing (NLP), researchers began exploring their application to visual tasks. This led to the development of Vision Transformers (ViT), which have revolutionized how we approach visual perception in AI and robotics.","sidebar":"tutorialSidebar"},"vision-language-action/vla-overview":{"id":"vision-language-action/vla-overview","title":"Module 5: VLA Models Overview","description":"Welcome to Module 5, where we explore the exciting paradigm of Vision-Language-Action (VLA) models in robotics. This module marks a significant shift from classical, hand-engineered control systems to \\"End-to-End Learning,\\" where robots learn directly from raw sensor data (pixels) to generate actions.","sidebar":"tutorialSidebar"}}}}')}}]);